import { useState, useEffect } from 'react';
import { getBuses, addBus, deleteBus, getRoutes, addRoute, getAllBookings, getAdminStats } from '../services/api';

export default function AdminDashboard() {
  const [tab,      setTab]      = useState('overview');
  const [buses,    setBuses]    = useState([]);
  const [routes,   setRoutes]   = useState([]);
  const [bookings, setBookings] = useState([]);
  const [stats,    setStats]    = useState({});
  const [loading,  setLoading]  = useState(true);
  const [showAddBus,   setShowAddBus]   = useState(false);
  const [showAddRoute, setShowAddRoute] = useState(false);
  const [busForm,   setBusForm]   = useState({ bus_number:'', bus_type:'AC Seater', capacity:'', driver_name:'' });
  const [routeForm, setRouteForm] = useState({ source:'', destination:'', distance:'', price_per_km:'1.50' });
  const [msg, setMsg] = useState('');

  useEffect(() => {
    Promise.all([getBuses(), getRoutes(), getAllBookings(), getAdminStats()])
      .then(([b, r, bk, s]) => { setBuses(b.data); setRoutes(r.data); setBookings(bk.data); setStats(s.data); })
      .catch(()=>{})
      .finally(()=>setLoading(false));
  }, []);

  const toast = (m) => { setMsg(m); setTimeout(()=>setMsg(''), 3000); };

  const handleAddBus = async () => {
    if (!busForm.bus_number || !busForm.capacity) { toast('Fill required fields'); return; }
    try {
      const res = await addBus({ ...busForm, capacity: parseInt(busForm.capacity), amenities: [] });
      setBuses(p=>[...p, res.data]); setShowAddBus(false);
      setBusForm({ bus_number:'', bus_type:'AC Seater', capacity:'', driver_name:'' });
      toast('Bus added successfully!');
    } catch (err) { toast(err.response?.data?.error || 'Failed'); }
  };

  const handleDeleteBus = async (id) => {
    if (!window.confirm('Delete this bus?')) return;
    try { await deleteBus(id); setBuses(p=>p.filter(b=>b.bus_id!==id)); toast('Bus deleted'); }
    catch (err) { toast(err.response?.data?.error || 'Failed'); }
  };

  const handleAddRoute = async () => {
    if (!routeForm.source || !routeForm.destination || !routeForm.distance) { toast('Fill required fields'); return; }
    try {
      const res = await addRoute({ ...routeForm, distance: parseInt(routeForm.distance), price_per_km: parseFloat(routeForm.price_per_km) });
      setRoutes(p=>[...p, res.data]); setShowAddRoute(false);
      setRouteForm({ source:'', destination:'', distance:'', price_per_km:'1.50' });
      toast('Route added!');
    } catch (err) { toast(err.response?.data?.error || 'Failed'); }
  };

  if (loading) return <div className="spinner" style={{marginTop:'4rem'}} />;

  return (
    <div className="page">
      {msg && <div style={{position:'fixed',bottom:'2rem',right:'2rem',background:'#10b981',color:'white',padding:'1rem 1.5rem',borderRadius:12,boxShadow:'0 8px 32px rgba(0,0,0,0.2)',zIndex:9999,fontSize:'0.9rem'}}>{msg}</div>}

      <div className="page-header" style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <div><h1 className="page-title">📊 Admin Dashboard</h1><p className="page-sub">Manage buses, routes, schedules and bookings</p></div>
        <span className="badge badge-info" style={{fontSize:'0.8rem',padding:'0.4rem 0.875rem'}}>🔧 Admin Mode</span>
      </div>

      {/* Stats */}
      <div className="grid-4" style={{marginBottom:'2rem'}}>
        {[{icon:'👥',label:'Total Users',value:stats.totalUsers||0,color:'#1a56db',bg:'rgba(26,86,219,0.1)'},{icon:'🚌',label:'Total Buses',value:buses.length,color:'#f97316',bg:'rgba(249,115,22,0.1)'},{icon:'🎫',label:'Total Bookings',value:stats.totalBookings||0,color:'#10b981',bg:'rgba(16,185,129,0.1)'},{icon:'💰',label:'Revenue',value:`₹${Math.round(stats.totalRevenue||0)}`,color:'#8b5cf6',bg:'rgba(139,92,246,0.1)'}].map(s=>(
          <div key={s.label} className="card">
            <div style={{width:52,height:52,borderRadius:14,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'1.4rem',background:s.bg,marginBottom:'1rem'}}>{s.icon}</div>
            <div style={{fontSize:'2rem',fontWeight:800,color:s.color,letterSpacing:-1}}>{s.value}</div>
            <div style={{fontSize:'0.85rem',color:'#64748b',marginTop:'0.25rem'}}>{s.label}</div>
          </div>
        ))}
      </div>

      <div className="tabs">
        {[['overview','Overview'],['buses','Buses'],['routes','Routes'],['bookings','Bookings']].map(([v,l])=>(
          <button key={v} className={`tab ${tab===v?'active':''}`} onClick={()=>setTab(v)}>{l}</button>
        ))}
      </div>

      {/* BUSES */}
      {tab==='buses' && (
        <div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
            <h3 style={{fontWeight:700}}>Fleet ({buses.length})</h3>
            <button className="btn btn-primary btn-sm" onClick={()=>setShowAddBus(true)}>+ Add Bus</button>
          </div>
          <div style={{overflowX:'auto'}}>
            <table className="data-table">
              <thead><tr><th>Bus Number</th><th>Type</th><th>Capacity</th><th>Driver</th><th>Amenities</th><th>Actions</th></tr></thead>
              <tbody>
                {buses.map(b=>(
                  <tr key={b.bus_id}>
                    <td style={{fontWeight:700}}>{b.bus_number}</td>
                    <td><span className="badge badge-info">{b.bus_type}</span></td>
                    <td>{b.capacity}</td>
                    <td>{b.driver_name||'—'}</td>
                    <td style={{fontSize:'0.8rem'}}>{(b.amenities||[]).join(', ')||'—'}</td>
                    <td><button className="btn btn-sm btn-danger" onClick={()=>handleDeleteBus(b.bus_id)}>Delete</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ROUTES */}
      {tab==='routes' && (
        <div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
            <h3 style={{fontWeight:700}}>Routes ({routes.length})</h3>
            <button className="btn btn-primary btn-sm" onClick={()=>setShowAddRoute(true)}>+ Add Route</button>
          </div>
          <div style={{overflowX:'auto'}}>
            <table className="data-table">
              <thead><tr><th>ID</th><th>From</th><th>To</th><th>Distance</th><th>Price/km</th><th>Base Fare</th></tr></thead>
              <tbody>
                {routes.map(r=>(
                  <tr key={r.route_id}>
                    <td style={{fontWeight:700}}>#{r.route_id}</td>
                    <td>{r.source}</td><td>{r.destination}</td>
                    <td>{r.distance} km</td>
                    <td>₹{r.price_per_km}</td>
                    <td style={{fontWeight:700,color:'#1a56db'}}>₹{Math.round(r.distance*r.price_per_km)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* BOOKINGS */}
      {tab==='bookings' && (
        <div>
          <h3 style={{fontWeight:700,marginBottom:'1rem'}}>All Bookings ({bookings.length})</h3>
          <div style={{overflowX:'auto'}}>
            <table className="data-table">
              <thead><tr><th>ID</th><th>Passenger</th><th>Route</th><th>Date</th><th>Seats</th><th>Amount</th><th>Status</th></tr></thead>
              <tbody>
                {bookings.map(b=>(
                  <tr key={b.booking_id}>
                    <td style={{fontWeight:700}}>#{b.booking_id}</td>
                    <td>{b.passenger_name}</td>
                    <td>{b.source} → {b.destination}</td>
                    <td>{b.travel_date ? new Date(b.travel_date).toLocaleDateString('en-IN',{day:'numeric',month:'short'}) : '—'}</td>
                    <td>{b.seats_booked}</td>
                    <td style={{fontWeight:700}}>₹{b.total_amount}</td>
                    <td><span className={`badge ${b.status==='confirmed'?'badge-success':b.status==='cancelled'?'badge-error':'badge-warning'}`}>{b.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* OVERVIEW */}
      {tab==='overview' && (
        <div className="grid-2">
          <div className="card">
            <h3 style={{fontWeight:700,marginBottom:'1rem'}}>📈 Revenue Breakdown</h3>
            {[['Today',0.12],['This Week',0.45],['This Month',0.8],['Total',1]].map(([p,m])=>(
              <div key={p} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'0.75rem',background:'#f1f5f9',borderRadius:10,marginBottom:'0.5rem'}}>
                <span style={{fontSize:'0.875rem',color:'#64748b'}}>{p}</span>
                <span style={{fontWeight:700,color:'#1a56db'}}>₹{Math.round((stats.totalRevenue||0)*m)}</span>
              </div>
            ))}
          </div>
          <div className="card">
            <h3 style={{fontWeight:700,marginBottom:'1rem'}}>🚌 Fleet Status</h3>
            {buses.slice(0,5).map(b=>(
              <div key={b.bus_id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'0.75rem',background:'#f1f5f9',borderRadius:10,marginBottom:'0.5rem'}}>
                <div><div style={{fontWeight:600,fontSize:'0.875rem'}}>{b.bus_number}</div><div style={{fontSize:'0.72rem',color:'#64748b'}}>{b.bus_type} · {b.capacity} seats</div></div>
                <span className="badge badge-success">Active</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ADD BUS MODAL */}
      {showAddBus && (
        <div className="modal-overlay">
          <div className="modal">
            <div className="modal-header"><h3 className="modal-title">Add New Bus</h3><button className="modal-close" onClick={()=>setShowAddBus(false)}>✕</button></div>
            <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>
              <div className="form-group"><label>Bus Number *</label><input className="form-control" placeholder="MH-12-XX-0000" value={busForm.bus_number} onChange={e=>setBusForm({...busForm,bus_number:e.target.value})} /></div>
              <div className="form-group"><label>Bus Type *</label>
                <select className="form-control" value={busForm.bus_type} onChange={e=>setBusForm({...busForm,bus_type:e.target.value})}>
                  {['AC Sleeper','Non-AC Seater','AC Seater','Luxury Volvo'].map(t=><option key={t}>{t}</option>)}
                </select>
              </div>
              <div className="input-row">
                <div className="form-group"><label>Capacity *</label><input className="form-control" type="number" placeholder="40" value={busForm.capacity} onChange={e=>setBusForm({...busForm,capacity:e.target.value})} /></div>
                <div className="form-group"><label>Driver Name</label><input className="form-control" placeholder="Driver name" value={busForm.driver_name} onChange={e=>setBusForm({...busForm,driver_name:e.target.value})} /></div>
              </div>
              <div style={{display:'flex',gap:'0.75rem',justifyContent:'flex-end'}}>
                <button className="btn btn-outline" onClick={()=>setShowAddBus(false)}>Cancel</button>
                <button className="btn btn-primary" onClick={handleAddBus}>Add Bus</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ADD ROUTE MODAL */}
      {showAddRoute && (
        <div className="modal-overlay">
          <div className="modal">
            <div className="modal-header"><h3 className="modal-title">Add New Route</h3><button className="modal-close" onClick={()=>setShowAddRoute(false)}>✕</button></div>
            <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>
              <div className="input-row">
                <div className="form-group"><label>From *</label><input className="form-control" placeholder="Mumbai" value={routeForm.source} onChange={e=>setRouteForm({...routeForm,source:e.target.value})} /></div>
                <div className="form-group"><label>To *</label><input className="form-control" placeholder="Pune" value={routeForm.destination} onChange={e=>setRouteForm({...routeForm,destination:e.target.value})} /></div>
              </div>
              <div className="input-row">
                <div className="form-group"><label>Distance (km) *</label><input className="form-control" type="number" placeholder="150" value={routeForm.distance} onChange={e=>setRouteForm({...routeForm,distance:e.target.value})} /></div>
                <div className="form-group"><label>Price/km (₹)</label><input className="form-control" type="number" step="0.1" placeholder="1.50" value={routeForm.price_per_km} onChange={e=>setRouteForm({...routeForm,price_per_km:e.target.value})} /></div>
              </div>
              <div style={{display:'flex',gap:'0.75rem',justifyContent:'flex-end'}}>
                <button className="btn btn-outline" onClick={()=>setShowAddRoute(false)}>Cancel</button>
                <button className="btn btn-primary" onClick={handleAddRoute}>Add Route</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
